import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useLanguage } from '../App';
import s from './Chat.module.css';

/* ── Axios instance ─────────────────────────────────────────────────────── */
const api = axios.create({ baseURL: 'http://localhost:8000', headers: { 'Content-Type': 'application/json' } });

// Injecte le token JWT dans chaque requête
api.interceptors.request.use(config => {
  const t = localStorage.getItem('awal_token');
  if (t) config.headers.Authorization = `Bearer ${t}`;
  return config;
});

// 401 → token expiré/invalide → vide localStorage et redirige vers /login
api.interceptors.response.use(
  res => res,
  err => {
    if (err?.response?.status === 401) {
      localStorage.removeItem('awal_token');
      localStorage.removeItem('awal_username');
      window.location.href = '/login';
    }
    return Promise.reject(err);
  }
);

// ── 5 LLM Models ───────────────────────────────────────────
const MODELS = [
  { id: 'mistral-small', label: 'Mistral Small', provider: 'Mistral', desc: 'Rapide et efficace',    color: '#f97316' },
  { id: 'mistral-nemo',  label: 'Mistral Nemo',  provider: 'Mistral', desc: 'Multilingue avancé',   color: '#f97316' },
  { id: 'llama-3.1-8b',  label: 'Llama 3.1 8B',  provider: 'Groq',    desc: 'Ultra rapide (Groq)',  color: '#8b5cf6' },
  { id: 'gemini-flash',  label: 'Gemini 1.5 Flash', provider: 'Google', desc: 'Long contexte',      color: '#3b82f6' },
  { id: 'command-r',     label: 'Command R',      provider: 'Cohere',  desc: 'Raisonnement RAG',    color: '#10b981' },
];

// ── Translations ────────────────────────────────────────────
const T = {
  fr: {
    newChat: 'Nouveau chat', today: "Aujourd'hui", days30: '30 derniers jours',
    settings: 'Paramètres', signOut: 'Déconnexion',
    welcomeSub: 'Votre assistant intelligent pour la langue et la culture amazighe.',
    placeholder: 'Pose ta question en amazigh, français ou darija...',
    hint: 'Entrée pour envoyer · Shift+Entrée pour nouvelle ligne',
    selectDomain: 'Choisis un domaine pour commencer',
    changeDomain: 'Changer',
    examples: 'Exemples', capabilities: 'Capacités', limitations: 'Limites',
    ex1: 'Azul ! Matta tgim ?', ex2: 'Suqel awal "tafukt" s tefransist', ex3: 'Acu d Yennayer ?',
    cap1: 'Répond en Tamazight latinisé', cap2: 'Détecte le dialecte amazigh', cap3: 'Traduit vers français/arabe',
    lim1: 'Peut faire des erreurs dialectales', lim2: 'Vocabulaire technique limité', lim3: 'Ne connaît pas les événements récents',
  },
  en: {
    newChat: 'New chat', today: 'Today', days30: '30 days',
    settings: 'Settings', signOut: 'Sign out',
    welcomeSub: 'Your smart assistant for the Amazigh language and culture.',
    placeholder: 'Ask in Amazigh, French or Darija...',
    hint: 'Enter to send · Shift+Enter for new line',
    selectDomain: 'Choose a domain to get started',
    changeDomain: 'Change',
    examples: 'Examples', capabilities: 'Capabilities', limitations: 'Limitations',
    ex1: 'Azul ! Matta tgim ?', ex2: 'Translate "tafukt" to English', ex3: 'What is Yennayer ?',
    cap1: 'Responds in latinized Tamazight', cap2: 'Detects Amazigh dialect', cap3: 'Translates to French/Arabic',
    lim1: 'May make dialect errors', lim2: 'Limited technical vocabulary', lim3: "Doesn't know recent events",
  },
  ar: {
    newChat: 'محادثة جديدة', today: 'اليوم', days30: 'آخر 30 يومًا',
    settings: 'الإعدادات', signOut: 'تسجيل الخروج',
    welcomeSub: 'مساعدك الذكي للغة والثقافة الأمازيغية.',
    placeholder: 'اسأل بالأمازيغية أو الفرنسية أو الدارجة...',
    hint: 'Enter للإرسال · Shift+Enter لسطر جديد',
    selectDomain: 'اختر مجالاً للبدء',
    changeDomain: 'تغيير',
    examples: 'أمثلة', capabilities: 'القدرات', limitations: 'الحدود',
    ex1: 'Azul ! Matta tgim ?', ex2: 'ترجم كلمة "tafukt"', ex3: 'ما هو Yennayer ؟',
    cap1: 'يجيب بالأمازيغية اللاتينية', cap2: 'يكتشف اللهجة الأمازيغية', cap3: 'يترجم إلى الفرنسية/العربية',
    lim1: 'قد يخطئ في اللهجة', lim2: 'مفردات تقنية محدودة', lim3: 'لا يعرف الأحداث الحديثة',
  },
};

// ── 6 Domains ───────────────────────────────────────────────
const DOMAINS = {
  fr: [
    { id: 'health',    label: 'Santé',       desc: 'Vocabulaire médical amazigh' },
    { id: 'economy',   label: 'Économie',    desc: 'Commerce et finances en amazigh' },
    { id: 'education', label: 'Éducation',   desc: 'Apprentissage et enseignement' },
    { id: 'culture',   label: 'Culture',     desc: 'Traditions et patrimoine amazigh' },
    { id: 'tech',      label: 'Technologie', desc: 'Terminologie tech en tamazight' },
    { id: 'daily',     label: 'Quotidien',   desc: 'Conversations de tous les jours' },
  ],
  en: [
    { id: 'health',    label: 'Health',      desc: 'Medical vocabulary in Amazigh' },
    { id: 'economy',   label: 'Economy',     desc: 'Commerce and finance in Amazigh' },
    { id: 'education', label: 'Education',   desc: 'Learning and teaching' },
    { id: 'culture',   label: 'Culture',     desc: 'Amazigh traditions and heritage' },
    { id: 'tech',      label: 'Technology',  desc: 'Tech terminology in Tamazight' },
    { id: 'daily',     label: 'Daily life',  desc: 'Everyday conversations' },
  ],
  ar: [
    { id: 'health',    label: 'الصحة',         desc: 'المفردات الطبية بالأمازيغية' },
    { id: 'economy',   label: 'الاقتصاد',      desc: 'التجارة والمالية بالأمازيغية' },
    { id: 'education', label: 'التعليم',        desc: 'التعلم والتدريس' },
    { id: 'culture',   label: 'الثقافة',        desc: 'التقاليد والتراث الأمازيغي' },
    { id: 'tech',      label: 'التكنولوجيا',    desc: 'المصطلحات التقنية بالتامازيغت' },
    { id: 'daily',     label: 'الحياة اليومية', desc: 'محادثات يومية' },
  ],
};

/* ── Model Selector (bottom, near input) ───────────────────── */
function ModelSelector({ activeModel, setActiveModel, language }) {
  const [open, setOpen] = useState(false);
  const ref  = useRef(null);
  const model = MODELS.find(m => m.id === activeModel) || MODELS[0];

  useEffect(() => {
    const handler = e => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  return (
    <div ref={ref} style={{ position: 'relative' }}>
      {/* Dropdown opens UPWARD */}
      {open && (
        <div style={{
          position: 'absolute', bottom: 'calc(100% + 8px)', left: 0,
          background: '#fff', border: '1px solid rgba(0,0,0,0.1)',
          borderRadius: 12, boxShadow: '0 -4px 32px rgba(0,0,0,0.12)',
          minWidth: 230, zIndex: 1000, overflow: 'hidden',
          animation: 'fadeUp 0.15s ease',
        }}>
          <div style={{ padding: '8px 12px 6px', fontSize: 11, fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
            {language === 'fr' ? 'Modèle LLM' : language === 'ar' ? 'نموذج LLM' : 'LLM Model'}
          </div>
          {MODELS.map(m => (
            <button
              key={m.id}
              onClick={() => { setActiveModel(m.id); setOpen(false); }}
              style={{
                width: '100%', display: 'flex', alignItems: 'center', gap: 10,
                padding: '9px 12px', border: 'none',
                background: activeModel === m.id ? 'rgba(249,115,22,0.06)' : 'transparent',
                cursor: 'pointer', textAlign: 'left', transition: 'background 0.1s',
              }}
              onMouseEnter={e => { if (activeModel !== m.id) e.currentTarget.style.background = '#f9fafb'; }}
              onMouseLeave={e => { if (activeModel !== m.id) e.currentTarget.style.background = 'transparent'; }}
            >
              <span style={{ width: 10, height: 10, borderRadius: '50%', background: m.color, flexShrink: 0 }} />
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 500, color: '#111827' }}>{m.label}</div>
                <div style={{ fontSize: 11, color: '#9ca3af' }}>{m.provider} · {m.desc}</div>
              </div>
              {activeModel === m.id && (
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#f97316" strokeWidth="2.5">
                  <polyline points="20 6 9 17 4 12" />
                </svg>
              )}
            </button>
          ))}
        </div>
      )}

      {/* Trigger button — minimal, like Claude's */}
      <button
        onClick={() => setOpen(v => !v)}
        style={{
          display: 'flex', alignItems: 'center', gap: 5,
          background: 'transparent', border: 'none',
          borderRadius: 6, padding: '4px 8px', cursor: 'pointer',
          fontSize: 12, fontWeight: 500, color: '#6b7280',
          transition: 'color 0.15s',
        }}
        onMouseEnter={e => e.currentTarget.style.color = '#111827'}
        onMouseLeave={e => e.currentTarget.style.color = '#6b7280'}
      >
        <span style={{ width: 8, height: 8, borderRadius: '50%', background: model.color, flexShrink: 0 }} />
        <span>{model.label}</span>
        <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"
          style={{ transform: open ? 'rotate(180deg)' : 'rotate(0)', transition: 'transform 0.2s' }}>
          <polyline points="6 9 12 15 18 9" />
        </svg>
      </button>
    </div>
  );
}

/* ── Main Component ─────────────────────────────────────────── */
export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();
  const { language } = useLanguage();

  const [showSettings, setShowSettings]   = useState(false);
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId]   = useState(null);
  const [messages, setMessages]           = useState([]);
  const [input, setInput]                 = useState('');
  const [loading, setLoading]             = useState(false);
  const [sidebarOpen, setSidebarOpen]     = useState(true);
  const [activeDomain, setActiveDomain]   = useState(null);
  const [activeModel, setActiveModel]     = useState('mistral-small');
  const [userInfo, setUserInfo]           = useState(null);

  const messagesEndRef = useRef(null);
  const textareaRef    = useRef(null);

  const t       = T[language];
  const domains = DOMAINS[language];

  // ── Fetch real user info on mount ──────────────────────────
  useEffect(() => {
    const fetchMe = async () => {
      try {
        const r = await api.get('/auth/me');
        setUserInfo(r.data);
      } catch {
        if (!user) nav('/login');
      }
    };
    fetchMe();
  }, []);

  // ── displayName: always real, never "Guest" if logged in ───
  const displayName = (() => {
    if (userInfo?.username?.trim()) return userInfo.username.trim();
    if (userInfo?.email)            return userInfo.email.split('@')[0];
    if (user?.username?.trim())     return user.username.trim();
    if (user?.email)                return user.email.split('@')[0];
    const stored = localStorage.getItem('awal_username');
    if (stored?.trim())             return stored.trim();
    return 'Guest';
  })();

  const displayEmail = userInfo?.email || user?.email || '';

  const getGreeting = () => {
    const h = new Date().getHours();
    if (h < 12) return language === 'fr' ? 'Bonjour' : language === 'ar' ? 'صباح الخير' : 'Good morning';
    if (h < 18) return language === 'fr' ? 'Bon après-midi' : language === 'ar' ? 'مساء الخير' : 'Good afternoon';
    return language === 'fr' ? 'Bonsoir' : language === 'ar' ? 'مساء الخير' : 'Good evening';
  };

  useEffect(() => { loadConversations(); }, []);
  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const loadConversations = async () => {
    try {
      const r = await api.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch (err) { console.error(err); }
  };

  const loadConversation = async (convId) => {
    try {
      const r = await api.get(`/conversations/${convId}/messages`);
      setMessages(r.data.messages.map(m => ({ role: m.sender === 'user' ? 'user' : 'bot', content: m.content })));
      setActiveConvId(convId);
    } catch (err) { console.error(err); }
  };

  const deleteConversation = async (id, e) => {
    e.stopPropagation();
    try {
      await api.delete(`/conversations/${id}`);
      setConversations(prev => prev.filter(c => c.id !== id));
      if (activeConvId === id) { setActiveConvId(null); setMessages([]); }
    } catch (err) { console.error(err); }
  };

  const newConversation = () => {
    setActiveConvId(null); setMessages([]); setActiveDomain(null);
    textareaRef.current?.focus();
  };

  const handleInputChange = e => {
    setInput(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 200) + 'px';
  };

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    setMessages(prev => [...prev, { role: 'user', content: text }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);

    try {
      const r = await api.post('/chat', {
        message: text,
        conversation_id: activeConvId,
        domain: activeDomain || null,
        model: activeModel,
      });
      setMessages(prev => [...prev, { role: 'bot', content: r.data.response }]);
      if (!activeConvId && r.data.conversation_id) {
        setActiveConvId(r.data.conversation_id);
        loadConversations();
      }
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'bot', content: 'Erreur de connexion. Veuillez réessayer.' }]);
    } finally { setLoading(false); }
  }, [input, loading, activeConvId, activeDomain, activeModel]);

  const now     = new Date();
  const grouped = conversations.reduce((acc, c) => {
    const d    = new Date(c.updated_at || c.created_at);
    const diff = (now - d) / 86400000;
    if (diff < 1) acc.today.push(c);
    else if (diff < 30) acc.days30.push(c);
    return acc;
  }, { today: [], days30: [] });

  const activeDomainObj = domains.find(d => d.id === activeDomain);
  const activeModelObj  = MODELS.find(m => m.id === activeModel) || MODELS[0];

  return (
    <div className={s.layout}>

      {/* Settings Modal */}
      {showSettings && (
        <div className={s.modalOverlay} onClick={() => setShowSettings(false)}>
          <div className={s.modal} onClick={e => e.stopPropagation()}>
            <div className={s.modalHeader}>
              <h3>{t.settings}</h3>
              <button className={s.closeModal} onClick={() => setShowSettings(false)}>×</button>
            </div>
            <div className={s.modalBody}>
              <p style={{ fontSize: 13, color: '#6b7280' }}>
                {language === 'fr' ? "La langue est définie depuis la page d'accueil."
                  : language === 'ar' ? 'يتم تحديد اللغة من الصفحة الرئيسية.'
                  : 'Language is set from the home page.'}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideHeader}>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" />
            </svg>
            {t.newChat}
          </button>
        </div>

        <div className={s.sideContent}>
          {grouped.today.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.today}</div>
              {grouped.today.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
          {grouped.days30.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.days30}</div>
              {grouped.days30.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className={s.sideFooter}>
          <button className={s.userBtn}>
            <div className={s.userAvatar}>{displayName[0]?.toUpperCase()}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{displayName}</div>
              <div className={s.userEmail}>{displayEmail}</div>
            </div>
          </button>
          <button className={s.signOutBtn} onClick={() => { logout(); nav('/'); }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
              <polyline points="16 17 21 12 16 7" />
              <line x1="21" y1="12" x2="9" y2="12" />
            </svg>
            {t.signOut}
          </button>
        </div>
      </aside>

      {/* Main */}
      <main className={s.main}>
        <div className={s.mainHeader}>
          <div className={s.headerLeft}>
            <button className={s.menuBtn} onClick={() => setSidebarOpen(v => !v)}>☰</button>
            <div className={s.headerLogo}>
              <img src="/logo.png" alt="Logo" width={26} />
              <span>AWAL GPT</span>
            </div>
            {activeDomainObj && (
              <div className={s.headerDomainBadge}>
                <span>{activeDomainObj.label}</span>
                <button onClick={() => setActiveDomain(null)}>×</button>
              </div>
            )}
          </div>
          <div className={s.headerActions}>
            <button className={s.settingsBtn} onClick={() => setShowSettings(true)} title={t.settings}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                <circle cx="12" cy="12" r="3" />
                <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z" />
              </svg>
            </button>
          </div>
        </div>

        <div className={s.messagesArea}>
          <div className={s.messages}>
            {messages.length === 0 ? (
              <div className={s.welcome}>
                <div className={s.greetingRow}>
                  <span className={s.asterisk}>
                    <img src="/logo.png" alt="Logo" className={s.welcomeLogo} />
                  </span>
                  <h1 className={s.welcomeTitle}>
                    {getGreeting()}, <span className={s.greetingName}>{displayName}</span>
                  </h1>
                </div>
                <p className={s.welcomeSub}>{t.welcomeSub}</p>

                {!activeDomain ? (
                  <div className={s.domainSection}>
                    <p className={s.domainSectionLabel}>{t.selectDomain}</p>
                    <div className={s.domainGrid}>
                      {domains.map(d => (
                        <button key={d.id} className={s.domainCard} onClick={() => setActiveDomain(d.id)}>
                          <span className={s.domainCardLabel}>{d.label}</span>
                          <span className={s.domainCardDesc}>{d.desc}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div className={s.activeDomainWelcome}>
                    <div>
                      <div className={s.activeDomainName}>{activeDomainObj?.label}</div>
                      <div className={s.activeDomainDesc}>{activeDomainObj?.desc}</div>
                    </div>
                    <button className={s.changeDomainBtn} onClick={() => setActiveDomain(null)}>
                      {t.changeDomain}
                    </button>
                  </div>
                )}

                <div className={s.welcomeGrid}>
                  <div className={s.welcomeCard}>
                    <h4>{t.examples}</h4>
                    {[t.ex1, t.ex2, t.ex3].map((ex, i) => (
                      <p key={i} onClick={() => setInput(ex)} style={{ cursor: 'pointer' }}>{ex}</p>
                    ))}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.capabilities}</h4>
                    {[t.cap1, t.cap2, t.cap3].map((c, i) => (
                      <p key={i} className={s.capability}>{c}</p>
                    ))}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.limitations}</h4>
                    {[t.lim1, t.lim2, t.lim3].map((l, i) => (
                      <p key={i} className={s.limitation}>{l}</p>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div key={idx} className={`${s.message} ${msg.role === 'user' ? s.messageUser : s.messageBot}`}>
                  <div className={s.messageAvatar}>
                    {msg.role === 'user'
                      ? <div className={s.userAvatarMsg}>{displayName[0]?.toUpperCase()}</div>
                      : <div className={s.botAvatar}>A</div>}
                  </div>
                  <div className={s.messageContent}>
                    <div className={s.messageName}>
                      {msg.role === 'user' ? displayName : 'AWAL GPT'}
                      {msg.role === 'bot' && (
                        <span style={{ fontSize: 11, color: '#9ca3af', marginLeft: 8, fontWeight: 400 }}>
                          {activeModelObj.label}
                        </span>
                      )}
                      {msg.role === 'user' && activeDomainObj && (
                        <span className={s.msgDomainTag}>{activeDomainObj.label}</span>
                      )}
                    </div>
                    <div className={s.messageText}>{msg.content}</div>
                  </div>
                </div>
              ))
            )}
            {loading && (
              <div className={`${s.message} ${s.messageBot}`}>
                <div className={s.messageAvatar}><div className={s.botAvatar}>A</div></div>
                <div className={s.messageContent}>
                  <div className={s.messageName}>AWAL GPT</div>
                  <div className={s.typing}><span /><span /><span /></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        {/* ── Input area with model selector INSIDE ── */}
        <div className={s.inputArea}>
          <div className={s.inputContainer}>
            {activeDomainObj && (
              <div className={s.inputDomainBar}>
                <span className={s.inputDomainLabel}>{activeDomainObj.label}</span>
                <span className={s.inputDomainAuto}>
                  {language === 'fr' ? '— domaine actif' : language === 'ar' ? '— المجال النشط' : '— active domain'}
                </span>
                <button className={s.inputDomainClose} onClick={() => setActiveDomain(null)}>×</button>
              </div>
            )}

            <div className={s.inputBox}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                placeholder={t.placeholder}
                value={input}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={loading}
              />
              <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="22" y1="2" x2="11" y2="13" />
                  <polygon points="22 2 15 22 11 13 2 9 22 2" />
                </svg>
              </button>
            </div>

            {/* ── Bottom bar: model selector LEFT, hint RIGHT ── */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 4 }}>
              <ModelSelector activeModel={activeModel} setActiveModel={setActiveModel} language={language} />
              <div className={s.inputHint}>{t.hint}</div>
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(6px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}
